const items = $input.all();

for (const item of items) {
  const rawInput = item.json.chatInput || item.json.body?.message || item.json.body?.query || '';
  const sessionId = item.json.sessionId || item.json.body?.sessionId || `session-${Date.now()}`;

  item.json = {
    chatInput: rawInput,
    sessionId: sessionId,
    source: item.json.chatInput ? 'chat' : 'api',
    receivedAt: new Date().toISOString()
  };
}

return items;

const item = $input.first();
const data = item?.json || {};

let sessionId = data.sessionId;
try {
  if (!sessionId) sessionId = $('Normalize Input').first().json.sessionId;
} catch (e) {}

let response = data.response || 'Xin lỗi, tôi không hiểu câu hỏi của bạn.';

// === LỌC THINKING LEAK ===
const isThinkingLine = (line) => {
  const t = line.trim();
  if (t === '') return false;
  if (/^(Okay|Let me|Now|Looking|I need|I will|First,|The context|Wait,|Check|So I|Let's|Based on|The user|According|I called|I have|I should|I'll|The tool|I got|Now I|This is|Alright|Sure|Make sure|Then a|Then the|structure it|Let me structure)/i.test(t)) return true;
  if (/\[from data\]|\[từ context\]|\[nội dung\]|\[information\]/i.test(t)) return true;
  if (/^[a-zA-Z\s,.\-:]+$/.test(t) && t.length > 15) return true;
  return false;
};

// === [MỚI] LỌC PLACEHOLDER LINES ===
// Xóa dòng nào chứa tên cột DB chưa được thay thế
const isPlaceholderLine = (line) => {
  const t = line.trim();
  // Các pattern placeholder từ AI template
  const placeholderPatterns = [
    /^\*\s*(doctor_name|hospital_name|hospital_address|average_rating|booking_link|detail_link)\s*$/i,
    /^\-\s*(doctor_name|hospital_name|hospital_address|average_rating|booking_link|detail_link)\s*$/i,
    /^(doctor_name|hospital_name|hospital_address|average_rating|booking_link|detail_link)\s*$/i,
    // Dòng chỉ chứa format hint như "(CHỈ HIỂN THỊ NẾU...)"
    /^\(CHỈ HIỂN THỊ/i,
    /^\(ONLY SHOW/i,
  ];
  return placeholderPatterns.some(p => p.test(t));
};

const removePlaceholderDoctorBlock = (text) => {
  const lines = text.split('\n');
  const result = [];
  let inDoctorBlock = false;
  let blockBuffer = [];
  let blockHasRealData = false;

  for (const line of lines) {
    const t = line.trim();

    // Phát hiện header "Gợi ý bác sĩ"
    if (/👨[‍⚕️]?\s*Gợi ý bác sĩ/i.test(t) || /Gợi ý bác sĩ phù hợp/i.test(t)) {
      inDoctorBlock = true;
      blockBuffer = [line];
      blockHasRealData = false;
      continue;
    }

    if (inDoctorBlock) {
      // Kết thúc block khi gặp section khác (bắt đầu bằng emoji section hoặc dòng trống sau nội dung)
      const isNewSection = /^[🛡️⚠️📌💊🚨👉]/.test(t) && t.length > 3;
      if (isNewSection) {
        // Flush block: chỉ giữ nếu có dữ liệu thực
        if (blockHasRealData) {
          result.push(...blockBuffer);
        }
        inDoctorBlock = false;
        blockBuffer = [];
        result.push(line);
        continue;
      }

      // Kiểm tra dòng có phải placeholder không
      if (isPlaceholderLine(line)) {
        blockBuffer.push(line); // ghi vào buffer nhưng đánh dấu là fake
      } else if (t !== '') {
        blockHasRealData = true; // dòng có nội dung thực
        blockBuffer.push(line);
      } else {
        blockBuffer.push(line);
      }
    } else {
      result.push(line);
    }
  }

  // Flush buffer cuối nếu còn
  if (inDoctorBlock && blockHasRealData) {
    result.push(...blockBuffer);
  }

  return result.join('\n');
};

// Apply filter
let lines = response.split('\n');
let cleanLines = [];
let foundRealContent = false;

for (let i = 0; i < lines.length; i++) {
  const t = lines[i].trim();
  if (isPlaceholderLine(lines[i])) continue;

  if (!foundRealContent) {
    if (isThinkingLine(t)) continue;
    const hasRealEmoji = /^[📌💊⚠️🛡️🚨]/.test(t) && !/\[from data\]|\[từ context\]/.test(t);
    const hasVietnamese = /[àáạảãâầấậẩẫăằắặẳẵèéẹẻẽêềếệểễìíịỉĩòóọỏõôồốộổỗơờớợởỡùúụủũưừứựửữỳýỵỷỹđ]/i.test(t);
    if (hasRealEmoji || hasVietnamese || t.startsWith('🚨')) {
      foundRealContent = true;
      cleanLines.push(lines[i]);
    }
  } else {
    cleanLines.push(lines[i]);
  }
}

response = cleanLines.join('\n').trim();
response = removePlaceholderDoctorBlock(response); 
if (response.length < 20) {
  response = data.response || 'Xin lỗi, tôi không hiểu câu hỏi của bạn.';
}

// === PARSE BOOKING DATA ===
const doctorIdMatch = response.match(/doctorId[=\/:]\s*([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})/i);
const doctorId = doctorIdMatch?.[1] ?? null;

const doctorNameMatch = response.match(/[-*]\s*(BS\.\s*[^\n\-*📌🛡️👨]+)/);
const doctorName = doctorNameMatch?.[1]?.trim() ?? null;

const hospitalMatch = response.match(/[-*]\s*(Bệnh viện[^\n]+|Phòng khám[^\n]+)/);
const hospitalName = hospitalMatch?.[1]?.trim() ?? null;

const ratingMatch = response.match(/(\d+\.?\d*)[\s]*[⭐★]/);
const rating = ratingMatch ? parseFloat(ratingMatch[1]) : null;

// === CLEAN MESSAGE ===
// const cleanMessage = response
//   .replace(/[-*]\s*Đặt lịch khám:\s*https?:\/\/[^\s\n]+/g, '')
//   .replace(/[-*]\s*Xem chi tiết:\s*https?:\/\/[^\s\n]+/g, '')
//   .replace(/https?:\/\/[^\s\n]+/g, '')
//   .replace(/\n{3,}/g, '\n\n')
//   .trim();

const cleanMessage = response
  .replace(/[-*]\s*Đặt lịch khám:\s*(https?:\/\/[^\s\n]+)/g, '[📅 Đặt lịch khám]($1)')
  .replace(/[-*]\s*Xem chi tiết bác sĩ:\s*(https?:\/\/[^\s\n]+)/g, '[👤 Xem chi tiết bác sĩ]($1)')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

// === AUTO-DETECT SEVERITY ===
const isEmergency = /🚨|gọi 115|cấp cứu ngay|đến bệnh viện ngay/i.test(response);
const severity = isEmergency ? 'emergency' : (data.severity || 'normal');
const responseType = isEmergency ? 'emergency' : (data.responseType || 'general');

// === BUILD FINAL RESPONSE ===
const finalResponse = {
  success: true,
  data: {
    message: cleanMessage,
    type: responseType,
    severity,
    timestamp: new Date().toISOString(),
    disclaimer: isEmergency
      ? null
      : '💙 Thông tin này chỉ mang tính tham khảo. Vui lòng tham khảo bác sĩ để được tư vấn chính xác.',
    suggestedActions: isEmergency
      ? ['🚨 Gọi cấp cứu 115 ngay lập tức', 'Đến bệnh viện/phòng cấp cứu gần nhất', 'Giữ bình tĩnh và ngồi thẳng']
      : ['Theo dõi triệu chứng trong vài ngày', 'Gặp bác sĩ nếu không thuyên giảm', 'Giữ vệ sinh và nghỉ ngơi đầy đủ'],

    ...(doctorId ? {
      action: 'OPEN_BOOKING',
      bookingData: {
        doctorId,
        ...(doctorName   ? { doctorName }   : {}),
        ...(hospitalName ? { hospitalName } : {}),
        ...(rating       ? { doctorRating: rating } : {}),
      }
    } : {})
  },
  meta: {
    sessionId: sessionId || 'unknown',
    queryType: responseType,
    processedAt: new Date().toISOString()
  }
};

return [{ json: finalResponse }];

const bookingPayload = $input.first().json.body || $input.first().json;

const {
  sessionId,
  doctorId,
  doctorName,
  selectedDate,
  selectedSlot,
  visitType,
} = bookingPayload;

if (!sessionId) {
  throw new Error('sessionId is required');
}

const bookingMemoryText =
  `[HỆ THỐNG - Lịch đặt thành công] ` +
  `Bệnh nhân vừa đặt lịch khám với ${doctorName ?? 'bác sĩ'} ` +
  `(doctorId: ${doctorId}), ` +
  `ngày ${selectedDate}, giờ ${selectedSlot}, ` +
  `hình thức: ${visitType === 'VIDEO' ? 'Video call' : 'Trực tiếp'}. ` +
  `Trạng thái: CONFIRMED.`;

return [{
  json: {
    sessionId,
    bookingMemoryText,
    doctorId,
    doctorName,
    selectedDate,
    selectedSlot,
    visitType,
  }
}];

const $json = $input.first().json;

const confirmResponse = {
  success: true,
  data: {
    message:
      `✅ Lịch khám đã được xác nhận!\n\n` +
      `📅 ${$json.selectedDate} lúc ${$json.selectedSlot}\n\n` +
      `👨⚕️ ${$json.doctorName ?? 'Bác sĩ'}\n\n` +
      `📋 Hình thức: ${$json.visitType === 'VIDEO' ? 'Video call' : 'Trực tiếp'}`,
    type: 'booking_confirmed',
    severity: 'success',
    timestamp: new Date().toISOString(),
    suggestedActions: [
      'Xem lịch hẹn của tôi',
      'Chuẩn bị gì trước khi khám?',
      'Đặt lịch khám khác',
    ],
  },
  meta: {
    sessionId: $json.sessionId,
    queryType: 'booking_confirmed',
    processedAt: new Date().toISOString(),
  }
};

return [{ json: confirmResponse }];
